code = """import json

# Access the file path
file_path = locals()['var_functions.query_db:4']

# Load the full business data
with open(file_path, 'r') as f:
    businesses = json.load(f)

# Filter businesses that accept credit cards and extract categories
credit_card_businesses = []
sample_businesses_output = []

for business in businesses:
    if business.get('attributes') and isinstance(business['attributes'], dict):
        if business['attributes'].get('BusinessAcceptsCreditCards') == 'True':
            description = business.get('description', '')
            business_id = business['business_id']
            
            # Parse categories from description
            categories = []
            if description:
                category_part = None
                
                if 'services in' in description:
                    category_part = description.split('services in')[-1]
                elif 'services, including' in description:
                    category_part = description.split('services, including')[-1]
                elif 'services including' in description:
                    category_part = description.split('services including')[-1]
                elif 'offers a' in description:
                    offers_part = description.split('offers a')[-1]
                    if ' in ' in offers_part:
                        category_part = offers_part.split(' in ')[-1]
                    elif ' including ' in offers_part:
                        category_part = offers_part.split(' including ')[-1]
                elif 'offers' in description and (' in ' in description or ' including ' in description):
                    offers_part = description.split('offers')[-1]
                    if ' in ' in offers_part:
                        category_part = offers_part.split(' in ')[-1]
                    elif ' including ' in offers_part:
                        category_part = offers_part.split(' including ')[-1]
                
                if category_part:
                    category_part = category_part.strip()
                    if category_part.endswith('.'):
                        category_part = category_part[:-1]
                    
                    parts = [p.strip() for p in category_part.split(',')]
                    
                    for part in parts:
                        if ' and ' in part and part.count(' and ') == 1:
                            sub_parts = [p.strip() for p in part.split(' and ')]
                            categories.extend(sub_parts)
                        elif ' and ' in part and part.count(' and ') > 1:
                            # Multiple "and" - split by the last one
                            last_and = part.rfind(' and ')
                            part1 = part[:last_and].strip()
                            part2 = part[last_and + 5:].strip()
                            categories.append(part1)
                            categories.append(part2)
                        else:
                            categories.append(part)
                    
                    categories = [cat for cat in categories if cat and cat not in ['']]
            
            credit_card_businesses.append({
                'business_id': business_id,
                'name': business['name'],
                'categories': categories,
                'description': description
            })

# Count categories and find Shopping businesses
category_counts = {}
shopping_businesses = []

for business in credit_card_businesses:
    for category in business['categories']:
        if category and category.strip():
            clean_category = category.strip()
            category_counts[clean_category] = category_counts.get(clean_category, 0) + 1
            
            # Collect Shopping category businesses
            if clean_category == 'Shopping' or clean_category.startswith('Shopping'):
                shopping_businesses.append(business['business_id'])

# Sort by count
top_categories = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)

print('__RESULT__:')
print(json.dumps({
    'top_categories': top_categories[:15],
    'top_category': top_categories[0] if top_categories else None,
    'shopping_businesses': shopping_businesses,
    'shopping_business_count': len(shopping_businesses)
}, indent=2))"""

